def generate(n, name, rarity, prompt, model=MODEL):
    """调用Pollinations.AI生成图片"""
    # 截断提示词（URL长度限制）
    p = prompt[:480]
    encoded = quote(p)
    url = (
        f"https://pollinations.ai/p/{encoded}"
        f"?width={WIDTH}&height={HEIGHT}"
        f"&model={model}&nologo=true"
        f"&seed={n * 7 + 42}"
    )
    response = requests.get(url, timeout=60)
    response.raise_for_status()
    return response.content

def main():
    Path(OUTPUT_DIR).mkdir(exist_ok=True)
    
    total = len(PROMPTS)
    done = 0
    failed = []
    
    print(f"\n龙虾文明宇宙 · 批量生图")
    print(f"总数: {total} 张")
    print(f"模型: {MODEL}")
    print(f"输出: {OUTPUT_DIR}/")
    print(f"从第 {START_FROM} 张开始")
    print("=" * 50)

    for i, (n, name, rarity, prompt) in enumerate(PROMPTS):
        n = int(n)
        
        # 断点续传
        if n < START_FROM:
            continue
            
        out_path = Path(OUTPUT_DIR) / f"{n}.png"
        
        # 已存在则跳过
        if out_path.exists():
            print(f"[跳过] {n}.png 已存在")
            done += 1
            continue
        
        print(f"[{n:03d}/{total}] {name} ({rarity})...", end=" ", flush=True)
        
        success = False
        for attempt in range(MAX_RETRY):
            try:
                img_data = generate(n, name, rarity, prompt)
                with open(out_path, 'wb') as f:
                    f.write(img_data)
                print(f"✓")
                done += 1
                success = True
                break
            except Exception as e:
                if attempt < MAX_RETRY - 1:
                    print(f"重试{attempt+1}...", end=" ", flush=True)
                    time.sleep(2)
                else:
                    print(f"✗ {e}")
                    failed.append((n, name))
        
        # 进度
        current = i + 1
        pct = int(current / total * 100)
        bar = "█" * (pct // 5) + "░" * (20 - pct // 5)
        print(f"  [{bar}] {pct}% · 完成:{done} 失败:{len(failed)}")
        
        if i < total - 1:
            time.sleep(DELAY)
    
    print("\n" + "=" * 50)
    print(f"完成！成功: {done} / 失败: {len(failed)}")
    
    if failed:
        print("\n失败列表:")
        for n, name in failed:
            print(f"  {n}.png - {name}")
        print("\n重新运行时修改 START_FROM 或删除失败的文件重试")
    
    print(f"\n图片保存在: {Path(OUTPUT_DIR).absolute()}")

if __name__ == "__main__":
    # 检查依赖
    try:
        import requests
    except ImportError:
        print("安装依赖: pip install requests")
        sys.exit(1)
    
    main()
